<template>
  <div id="card">
    <Row>
      <Col :offset="3" :span="11">
        <p>Cached Transactions List:</p>
        <Table border :data="trans" :columns="Columns2" stripe></Table>
        <!--<div style="margin: 10px 0;overflow: hidden">-->
          <!--<div style="float: right;">-->
            <!--<Page :total="total" :current="1" show-total @on-change="changePage" size="small"></Page>-->
          <!--</div>-->
        <!--</div>-->
      </Col>
      <Col :offset="2" :span="5">
        <Card class="cards">
          <p slot="title">
            <Icon type="social-bitcoin"></Icon>
            Create Balance
          </p>
          <a href="#" slot="extra" @click.prevent="createWallet">
            <Icon type="plus-round"></Icon>
            Create
          </a>
          <Input v-model="priv" placeholder="" clearable style="padding-right: 10%" class="input_card">
            <span slot="prepend">private key</span>
          </Input>
          <Input v-model="address" placeholder="" clearable style="padding-right: 10%" class="input_card">
            <span slot="prepend">address&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span>
          </Input>
        </Card>
        <Card class="cards">
          <p slot="title">
            <Icon type="cash"></Icon>

            Transaction
          </p>
          <a href="#" slot="extra" @click.prevent="sendToken">
            <Icon type="android-send"></Icon>
            Send
          </a>
          <Input v-model="from" placeholder="from" clearable style="padding-right: 10%" class="input_card"></Input>
          <Input v-model="to" placeholder="to" clearable style="padding-right: 10%" class="input_card"></Input>
          <Input v-model="amount" placeholder="amount" clearable style="padding-right: 10%" class="input_card"></Input>
        </Card>
        <Card class="cards">
          <p slot="title">
            <Icon type="cash"></Icon>
            Check Balance
          </p>
          <a href="#" slot="extra" @click.prevent="getBalance">
            <Icon type="android-send"></Icon>
            Check
          </a>
          <Input v-model="qaccount" placeholder="account" clearable style="padding-right: 10%" class="input_card"></Input>
        </Card>
      </Col>
    </Row>
  </div>
</template>

<script>
    export default {
        name: "FunctionCard",
      data(){
          return{
            trans:[],
            Columns2: [
              {
                title: 'Source',
                key: 'source',
                width: 250,
              },
              {
                title: 'Target',
                key: 'target',
                width: 250
              },
              {
                title: 'Value',
                key: 'value',
              }
            ],
            from: "",
            to: "",
            amount:"",
            qaccount:"",
            address: "",
            priv: ""
          }
      },
      mounted(){
          setInterval(this.getTrans, 1000);
      },
      methods:{
        getTrans() {
          let params = {
            "method": "GTAS_transPool",
            "params": [],
            "jsonrpc": "2.0",
            "id": "1"
          };
          this.$ajax({
            url: "/",
            method:"post",
            data: JSON.stringify(params)
          }).then(response => {
            let rdata = response.data;
            if (rdata.result !== undefined){
              rdata.result.data.sort(function (a, b) {
                return parseInt(a.value-b.value)
              });
              this.trans = rdata.result.data;
            }
          })
        },
        createWallet(){
          let params = {
            "method": "GTAS_newWallet",
            "params": [],
            "jsonrpc": "2.0",
            "id": "1"
          };
          this.$ajax({
            url: "/",
            method:"post",
            data: JSON.stringify(params)
          }).then(response => {
            let rdata = response.data;
            if (rdata.result !== undefined){
              this.address = rdata.result.data.address;
              this.priv = rdata.result.data.private_key;
            }
          })
        },
        sendToken(){
          let params = {
            "method": "GTAS_t",
            "params": [this.from, this.to, parseFloat(this.amount), ""],
            "jsonrpc": "2.0",
            "id": "1"
          };
          this.$ajax({
            url: "/",
            method:"post",
            data: JSON.stringify(params)
          }).then(response => {
            let rdata = response.data;
            if (rdata.result !== undefined){
              this.$Notice.success({
                title: 'succeed',
              });
            } else {
              this.$Notice.error({
                title: 'failed',
              });
            }
          })
        },
        getBalance(){
          let params = {
            "method": "GTAS_balance",
            "params": [this.qaccount],
            "jsonrpc": "2.0",
            "id": "1"
          };
          this.$ajax({
            url: "/",
            method:"post",
            data: JSON.stringify(params)
          }).then(response => {
            let rdata = response.data;
            if (rdata.result !== undefined){
              this.$Notice.success({
                desc:this.qaccount + '\nBalance: ' + rdata.result.data,
                title: "succeed"
              });
            } else {
              this.$Notice.error({
                title: 'check balance failed',
              });
            }
          })
        },
      }
    }
</script>

<style scoped>
#card{
  margin: 30px 0;
}
  .input_card{
    margin: 10px 10px 10px 10px;
  }
  .cards{
    margin: 0 0 30px 0;
  }
</style>



