<style scoped>

</style>
<template>
  <div>
    <message-card></message-card>
    <div>
      <Row>
        <Col span="18" offset="3">
          <p>Producers List:</p>
          <Table border stripe :columns="columns1" :data="nodes"></Table>
        </Col>
      </Row>
    </div>
  </div>
</template>


<script>
  import MessageCard from "./MessageCard"
export default {
  name: 'Dashboard',
  components: {MessageCard},
  component: [MessageCard],
  data () {
    return {
      columns1: [
        {
          title: 'Index',
          key: 'index',
          type:"index",
          width: 80,
        },
        {
          title: 'ID',
          key: 'id',
          width: 550
        },
        {
          title: 'IP Address',
          key: 'ip',
        },
        {
          title: 'Port',
          key: 'tcp_port',
        }
      ],
      nodes: [
      ]
    }
  },
  mounted(){
    setInterval(this.getNodes, 1000);
  },
  methods: {
    getNodes() {
      let params = {
        "method": "GTAS_connectedNodes",
        "params": [],
        "jsonrpc": "2.0",
        "id": "1"
      };
      this.$ajax({
        url: "/",
        method:"post",
        data: JSON.stringify(params)
      }).then(response => {
        let rdata = response.data;
        if (rdata.result !== undefined){
          rdata.result.data.sort(function (a, b) {
            return parseInt(a.ip.split(".")[3] + a.tcp_port) - parseInt(b.ip.split(".")[3] + b.tcp_port)
          });
          this.nodes = rdata.result.data;
        }
      })
    }
  }
}
</script>




