<template>
  <div>
    <Row id="blocks">
      <Col :offset="3" :span="18">
        <p>Block List:</p>
        <Table border :data="blocks" :columns="tableColumns1" stripe></Table>
        <div style="margin: 10px 0;overflow: hidden">
          <div style="float: right;">
            <Page :total="total" :current="1" show-total show-sizer @on-change="changePage" @on-page-size-change="changeSize"></Page>
          </div>
        </div>
      </Col>
    </Row>
  </div>
</template>

<script>
    export default {
        name: "BlockView",
      data () {
        return {
          blocks:[
          ],
          total:0,
          pageCount: 10,
          tableColumns1: [
            {
              title: 'Height',
              key: 'height',
              width: 80,
              sortType:"asc"
            },
            {
              title: 'Hash',
              key: 'hash',
              width:200
            },
            {
              title: 'PreHash',
              key: 'pre_hash',
              width: 200
            },
            {
              title: 'PreTime',
              key: 'pre_time',
              width: 100
            },
            {
              title: 'QueueNumber',
              key: 'queue_number',
              width: 100
            },
            {
              title: 'CurTime',
              key: 'cur_time',
              width: 100
            },
            {
              title: 'Castor',
              key: 'castor',
              width: 100
            },
            {
              title: 'GroupId',
              key: 'group_id',
              width: 100
            },
            {
              title: 'Signature',
              key: 'signature'
            }
          ]
        }
      },
      mounted() {
        setInterval(this.getBh, 1000);
      },
      methods: {
        getBh() {
          let params = {
            "method": "GTAS_blockHeight",
            "params": [],
            "jsonrpc": "2.0",
            "id": "1"
          };
          this.$ajax({
            url: "/",
            method:"post",
            data: JSON.stringify(params)
          }).then(response => {
            let rdata = response.data;
            if (rdata.result !== undefined){
              if (this.total===0 && rdata.result.data !== 0) {
                this.total = rdata.result.data;
                this.changePage(1);
              } else {
                this.total = rdata.result.data;
              }
            }
          })
        },
        syncBlock(height) {
          let params = {
            "method": "GTAS_getBlock",
            "params": [height],
            "jsonrpc": "2.0",
            "id": "1"
          };
          this.$ajax({
            url: "/",
            method:"post",
            data: JSON.stringify(params)
          }).then(response => {
            let rdata = response.data;
            if (rdata.result !== undefined){
              this.blocks.push(rdata.result.data)
            }
          })
        },
        changePage(num) {
          this.blocks = [];
          let offset = this.pageCount*(num-1);
          for (let i=offset+1; i <= offset+this.pageCount; i++) {
            if (i > this.total) {
              break
            }
            this.syncBlock(i);
          }
          console.log(num)
        },
        changeSize(count) {
          this.pageCount = count;
        }
      }
    }
</script>

<style scoped>
#blocks{
  margin: 30px 0;
}
</style>



