<template>
  <div id="mcard">
    <Row>
      <Col span="8" offset="3">
        <Card>
          <p slot="title">Last Block</p>
          <p>{{ bh }}</p>
        </Card>
      </Col>
      <Col span="8" offset="2">
        <Card>
          <p slot="title">Group Height</p>
          <p>{{ gh }}</p>
        </Card>
      </Col>
    </Row>
  </div>
</template>

<script>
    export default {
        name: "MessageCard",
      data () {
          return {
            bh: "0",
            gh: 0
          }
      },
      mounted() {
         setInterval(this.getbh, 1000);
         setInterval(this.getgh, 1000);
      },
      methods: {
        getbh() {
          let params = {
            "method": "GTAS_blockHeight",
            "params": [],
            "jsonrpc": "2.0",
            "id": "1"
          };
          this.$ajax({
            url: "/",
            method:"post",
            data: JSON.stringify(params)
          }).then(response => {
            let rdata = response.data;
            if (rdata.result !== undefined){
              this.bh = rdata.result.data;
            }
          })
        },
        getgh() {
          let params = {
            "method": "GTAS_groupHeight",
            "params": [],
            "jsonrpc": "2.0",
            "id": "1"
          };
          this.$ajax({
            url: "/",
            method:"post",
            data: JSON.stringify(params)
          }).then(response => {
            let rdata = response.data;
            if (rdata.result !== undefined){
              this.gh = rdata.result.data;
            }
          })
        },
      }
    }
</script>

<style scoped>
#mcard{
  margin: 30px 0;
}
</style>



